import PopularProduct from '../PopularProduct/PopularProduct';
import styles from './popular-products-list.module.css';
import { useEffect, useState } from 'react';
import { getPopularProducts } from '../../../api/products-api';
import useCartBtn from '../../../helpers/useCartBtn';
import useModal from '../../../helpers/useModal';
import ProductModal from '../../ProductModal/ProductModal';
import { RingLoader } from 'react-spinners';

const PopularProductsList = () => {
  const [items, setItems] = useState([]);
  const [isLoading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const { handleClick } = useCartBtn();
  const { isOpen, data: selectedProductId, openModal, closeModal } = useModal();

  useEffect(() => {
    const fetchPopularProducts = async () => {
      try {
        setLoading(true);
        const data = await getPopularProducts();
        setItems(data ? data : []);
      } catch (error) {
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };
    fetchPopularProducts();
  }, []);

  const elements = items?.map(item => (
    <PopularProduct
      key={item._id}
      product={item}
      openModal={() => {
        openModal(item._id);
      }}
      onClick={() => handleClick(item)}
    />
  ));

  return (
    <>
      {error && <p>{error}</p>}
      {isLoading ? (
        <RingLoader
          color="#586f1f"
          cssOverride={{
            display: 'block',
            margin: '100px auto',
          }}
        />
      ) : (
        <section className={styles.popular}>
          <h3 className={styles.title}>Popular products</h3>
          <ul className={styles.list}>{elements}</ul>
        </section>
      )}
      <ProductModal selectedProductId={selectedProductId} modalIsOpen={isOpen} setModalIsOpen={closeModal} />
    </>
  );
};
export default PopularProductsList;
